-- Phase-two basic seed data for attendance_db
-- Includes calendar_date, users, students, face features, and class enrollment history.
USE attendance_db;
START TRANSACTION;

-- calendar_date batch 1
AS incoming
ON DUPLICATE KEY UPDATE
  year_num = incoming.year_num,
  month_num = incoming.month_num,
  day_num = incoming.day_num;

-- calendar_date batch 2
AS incoming
ON DUPLICATE KEY UPDATE
  year_num = incoming.year_num,
  month_num = incoming.month_num,
  day_num = incoming.day_num;

-- calendar_date batch 3
AS incoming
ON DUPLICATE KEY UPDATE
  year_num = incoming.year_num,
  month_num = incoming.month_num,
  day_num = incoming.day_num;

-- student_info batch 1
AS incoming
ON DUPLICATE KEY UPDATE
  name = incoming.name,
  class_name = incoming.class_name,
  face_feature = incoming.face_feature,
  face_feature_hash = incoming.face_feature_hash,
  feature_version = incoming.feature_version,
  feature_updated_at = incoming.feature_updated_at,
  status = incoming.status;

-- class_enrollment_history batch 1
AS incoming
ON DUPLICATE KEY UPDATE
  left_at = incoming.left_at;

-- user_info batch 1
AS incoming
ON DUPLICATE KEY UPDATE
  username = incoming.username,
  password_hash = incoming.password_hash,
  role = incoming.role,
  student_id = incoming.student_id,
  status = incoming.status,
  token_version = incoming.token_version;

COMMIT;
